package cn.org.starpivot.mall.common;import cn.org.starpivot.api.mall.promotion.PromotionInternalClient;import cn.org.starpivot.api.mall.promotion.dto.*;import cn.org.starpivot.api.member.dto.MemberLevelDto;import cn.org.starpivot.common.domain.Result;import cn.org.starpivot.common.exception.BizException;import cn.org.starpivot.mall.portal.domain.bo.PortalOrderItemBo;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Component;import org.springframework.util.CollectionUtils;import java.util.List;import java.util.stream.Collectors;@Component@RequiredArgsConstructorpublic class PromotionFeignSupport {    private static final String ACTION = "营销服务";    private final PromotionInternalClient promotionInternalClient;    public SkuPriceRulesDto loadSkuPriceRules(List<Long> skuIds, MemberLevelDto level) {        SkuPriceRulesRequest request = new SkuPriceRulesRequest();        request.setSkuIds(skuIds);        if (level != null) {            request.setMemberLevelId(level.getId());            request.setIncludeMemberPrice(Integer.valueOf(1).equals(level.getPriviledgeMemberPrice()));        }        Result<SkuPriceRulesDto> result = promotionInternalClient.loadSkuPriceRules(request);        if (result == null || !result.isSuccess() || result.getData() == null) {            throw new BizException(result != null ? result.getMessage() : ACTION + "不可用");        }        return result.getData();    }    public CouponCalculateResultDto calculateCoupon(Long memberId, Long couponHistoryId, List<PortalOrderItemBo> items) {        CouponCalculateRequest request = new CouponCalculateRequest();        request.setMemberId(memberId);        request.setCouponHistoryId(couponHistoryId);        if (!CollectionUtils.isEmpty(items)) {            request.setItems(items.stream().map(this::toTrialItem).collect(Collectors.toList()));        }        Result<CouponCalculateResultDto> result = promotionInternalClient.calculateCoupon(request);        if (result == null || !result.isSuccess() || result.getData() == null) {            throw new BizException(result != null ? result.getMessage() : ACTION + "不可用");        }        return result.getData();    }    public void lockCoupon(Long memberId, Long couponHistoryId, Long orderId, String orderSn) {        if (couponHistoryId == null) {            return;        }        CouponConsumeRequest request = new CouponConsumeRequest();        request.setMemberId(memberId);        request.setCouponHistoryId(couponHistoryId);        request.setOrderId(orderId);        request.setOrderSn(orderSn);        unwrapVoid(promotionInternalClient.consumeCoupon(request));    }    public void confirmCoupon(Long orderId) {        if (orderId == null) {            return;        }        unwrapVoid(promotionInternalClient.confirmCouponByOrder(orderId));    }    public void releaseCoupon(Long orderId) {        if (orderId == null) {            return;        }        unwrapVoid(promotionInternalClient.releaseCouponByOrder(orderId));    }    public void releaseSeckillByOrderSn(String orderSn) {        if (orderSn == null || orderSn.isBlank()) {            return;        }        unwrapVoid(promotionInternalClient.releaseSeckillByOrderSn(orderSn));    }    private CouponTrialItemDto toTrialItem(PortalOrderItemBo item) {        CouponTrialItemDto dto = new CouponTrialItemDto();        dto.setSkuId(item.getSkuId());        dto.setQuantity(item.getQuantity());        return dto;    }    private void unwrapVoid(Result<Void> result) {        if (result == null || !result.isSuccess()) {            throw new BizException(result != null ? result.getMessage() : ACTION + "不可用");        }    }}